1	"use client";
2	
3	import type { JSX } from "react";
4	import {
5	  Field,
6	  FieldError,
7	  FieldLabel,
8	} from "@/components/ui/field";
9	import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
10	import { useIsHydrated } from "@/hooks/use-is-hydrated";
11	import {
12	  buildCategoryPath,
13	  type CategoryNode,
14	  findLevel1,
15	  findLevel2,
16	  resolveCategoryName,
17	} from "@/app/(main)/courses/new/_lib/categories";
18	import { useCourseBasicForm } from "@/app/(main)/courses/new/_components/course-basic-form-context";
19	
20	export function CategoryFields({
21	  tree,
22	}: {
23	  tree: CategoryNode[];
24	}): JSX.Element {
25	  const form = useCourseBasicForm();
26	  const disabled = !useIsHydrated();
27	
28	  const setResolved = (level1: string, level2: string, level3: string): void => {
29	    form.setFieldValue(
30	      "categoryName",
31	      resolveCategoryName(tree, level1, level2, level3),
32	    );
33	    form.setFieldValue(
34	      "categoryPath",
35	      buildCategoryPath(level1, level2, level3),
36	    );
37	  };
38	
39	  // 選択肢が 1 件しかない場合は自動選択して下位もチェーンする
40	  const cascadeFromLevel1 = (level1: string): void => {
41	    const level2Options = findLevel1(tree, level1)?.children ?? [];
42	    const level2 = level2Options.length === 1 ? level2Options[0]!.slug : "";
43	    form.setFieldValue("categoryLevel2", level2);
44	    cascadeFromLevel2(level1, level2);
45	  };
46	  const cascadeFromLevel2 = (level1: string, level2: string): void => {
47	    const level3Options =
48	      level2 === ""
49	        ? []
50	        : (findLevel2(tree, level1, level2)?.children ?? []);
51	    const level3 = level3Options.length === 1 ? level3Options[0]!.slug : "";
52	    form.setFieldValue("categoryLevel3", level3);
53	    setResolved(level1, level2, level3);
54	  };
55	
56	  return (
57	    <form.Subscribe
58	      selector={(state) =>
59	        [
60	          state.values.categoryLevel1,
61	          state.values.categoryLevel2,
62	        ] as const
63	      }
64	    >
65	      {([level1Value, level2Value]) => {
66	        const level2Options = findLevel1(tree, level1Value)?.children ?? [];
67	        const level3Options =
68	          findLevel2(tree, level1Value, level2Value)?.children ?? [];
69	        return (
70	          <div className="grid gap-4">
71	            <div className="grid gap-1">
72	              <span className="text-sm font-bold">
73	                カテゴリ
74	                <RequiredOptionalBadge required />
75	              </span>
76	              <p className="text-xs text-muted-foreground">
77	                大分類から順に選択します。
78	              </p>
79	            </div>
80	            <div className="grid gap-4 md:grid-cols-3">
81	              <form.Field name="categoryLevel1">
82	                {(field) => {
83	                  const showError =
84	                    field.state.meta.isBlurred && !field.state.meta.isValid;
85	                  return (
86	                    <Field data-invalid={showError}>
87	                      <FieldLabel htmlFor={field.name}>大分類</FieldLabel>
88	                      <select
89	                        id={field.name}
90	                        name={field.name}
91	                        aria-invalid={showError}
92	                        value={field.state.value}
93	                        onChange={(event) => {
94	                          const next = event.target.value;
95	                          field.handleChange(next);
96	                          cascadeFromLevel1(next);
97	                        }}
98	                        onBlur={field.handleBlur}
99	                        disabled={disabled}
100	                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
101	                      >
102	                        <option value="">選択してください</option>
103	                        {tree.map((node) => (
104	                          <option key={node.slug} value={node.slug}>
105	                            {node.name}
106	                          </option>
107	                        ))}
108	                      </select>
109	                      <FieldError
110	                        errors={showError ? field.state.meta.errors : []}
111	                      />
112	                    </Field>
113	                  );
114	                }}
115	              </form.Field>
116	
117	              <form.Field name="categoryLevel2">
118	                {(field) => {
119	                  const showError =
120	                    field.state.meta.isBlurred && !field.state.meta.isValid;
121	                  const level2Disabled =
122	                    disabled || level2Options.length === 0;
123	                  return (
124	                    <Field data-invalid={showError}>
125	                      <FieldLabel htmlFor={field.name}>中分類</FieldLabel>
126	                      <select
127	                        id={field.name}
128	                        name={field.name}
129	                        aria-invalid={showError}
130	                        value={field.state.value}
131	                        onChange={(event) => {
132	                          const next = event.target.value;
133	                          field.handleChange(next);
134	                          cascadeFromLevel2(level1Value, next);
135	                        }}
