export interface CategoryNode {
  slug: string;
  name: string;
  children?: CategoryNode[];
}

const maxDepth = 3;

/**
 * 各階層に「その他」を末尾追加し、葉に達するまで子を補完したツリーを返す。
 * API から取得した raw ツリーを 3 階層に揃えるために使う。
 */
export function fillToLeaf(
  nodes: CategoryNode[],
  depth: number = 1,
): CategoryNode[] {
  return [
    ...nodes.map((node) => fillNode(node, depth)),
    fillNode({ slug: "other", name: "その他" }, depth),
  ];
}

function fillNode(node: CategoryNode, depth: number): CategoryNode {
  if (depth === maxDepth) {
    return { slug: node.slug, name: node.name };
  }
  return {
    slug: node.slug,
    name: node.name,
    children: fillToLeaf(node.children ?? [], depth + 1),
  };
}

export function findLevel1(
  tree: CategoryNode[],
  slug: string,
): CategoryNode | undefined {
  return tree.find((node) => node.slug === slug);
}

export function findLevel2(
  tree: CategoryNode[],
  level1Slug: string,
  level2Slug: string,
): CategoryNode | undefined {
  return findLevel1(tree, level1Slug)?.children?.find(
    (node) => node.slug === level2Slug,
  );
}

export function findLevel3(
  tree: CategoryNode[],
  level1Slug: string,
  level2Slug: string,
  level3Slug: string,
): CategoryNode | undefined {
  return findLevel2(tree, level1Slug, level2Slug)?.children?.find(
    (node) => node.slug === level3Slug,
  );
}

export function buildCategoryPath(
  level1: string,
  level2: string,
  level3: string,
): string {
  return [level1, level2, level3].filter((slug) => slug !== "").join(".");
}

export function resolveCategoryName(
  tree: CategoryNode[],
  level1: string,
  level2: string,
  level3: string,
): string {
  if (level3) {
    return findLevel3(tree, level1, level2, level3)?.name ?? "";
  }
  if (level2) {
    return findLevel2(tree, level1, level2)?.name ?? "";
  }
  return findLevel1(tree, level1)?.name ?? "";
}

