"use client";

import type { JSX } from "react";
import {
  Field,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  buildCategoryPath,
  type CategoryNode,
  findLevel1,
  findLevel2,
  resolveCategoryName,
} from "@/app/(main)/courses/new/_lib/categories";
import { useCourseBasicForm } from "@/app/(main)/courses/new/_components/course-basic-form-context";

export function CategoryFields({
  tree,
}: {
  tree: CategoryNode[];
}): JSX.Element {
  const form = useCourseBasicForm();
  const disabled = !useIsHydrated();

  const setResolved = (level1: string, level2: string, level3: string): void => {
    form.setFieldValue(
      "categoryName",
      resolveCategoryName(tree, level1, level2, level3),
    );
    form.setFieldValue(
      "categoryPath",
      buildCategoryPath(level1, level2, level3),
    );
  };

  // 選択肢が 1 件しかない場合は自動選択して下位もチェーンする
  const cascadeFromLevel1 = (level1: string): void => {
    const level2Options = findLevel1(tree, level1)?.children ?? [];
    const level2 = level2Options.length === 1 ? level2Options[0]!.slug : "";
    form.setFieldValue("categoryLevel2", level2);
    cascadeFromLevel2(level1, level2);
  };
  const cascadeFromLevel2 = (level1: string, level2: string): void => {
    const level3Options =
      level2 === ""
        ? []
        : (findLevel2(tree, level1, level2)?.children ?? []);
    const level3 = level3Options.length === 1 ? level3Options[0]!.slug : "";
    form.setFieldValue("categoryLevel3", level3);
    setResolved(level1, level2, level3);
  };

  return (
    <form.Subscribe
      selector={(state) =>
        [
          state.values.categoryLevel1,
          state.values.categoryLevel2,
        ] as const
      }
    >
      {([level1Value, level2Value]) => {
        const level2Options = findLevel1(tree, level1Value)?.children ?? [];
        const level3Options =
          findLevel2(tree, level1Value, level2Value)?.children ?? [];
        return (
          <div className="grid gap-4">
            <div className="grid gap-1">
              <span className="text-sm font-bold">
                カテゴリ
                <RequiredOptionalBadge required />
              </span>
              <p className="text-xs text-muted-foreground">
                大分類から順に選択します。
              </p>
            </div>
            <div className="grid gap-4 md:grid-cols-3">
              <form.Field name="categoryLevel1">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>大分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) => {
                          const next = event.target.value;
                          field.handleChange(next);
                          cascadeFromLevel1(next);
                        }}
                        onBlur={field.handleBlur}
                        disabled={disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs"
                      >
                        <option value="">選択してください</option>
                        {tree.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel2">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  const level2Disabled =
                    disabled || level2Options.length === 0;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>中分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) => {
                          const next = event.target.value;
                          field.handleChange(next);
                          cascadeFromLevel2(level1Value, next);
                        }}
                        onBlur={field.handleBlur}
                        disabled={level2Disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
                      >
                        <option value="">
                          {level2Options.length === 0
                            ? "—"
                            : "選択してください"}
                        </option>
                        {level2Options.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>

              <form.Field name="categoryLevel3">
                {(field) => {
                  const showError =
                    field.state.meta.isBlurred && !field.state.meta.isValid;
                  const level3Disabled =
                    disabled || level3Options.length === 0;
                  return (
                    <Field data-invalid={showError}>
                      <FieldLabel htmlFor={field.name}>小分類</FieldLabel>
                      <select
                        id={field.name}
                        name={field.name}
                        aria-invalid={showError}
                        value={field.state.value}
                        onChange={(event) => {
                          const next = event.target.value;
                          field.handleChange(next);
                          setResolved(level1Value, level2Value, next);
                        }}
                        onBlur={field.handleBlur}
                        disabled={level3Disabled}
                        className="h-9 rounded-md border bg-transparent px-3 text-sm shadow-xs disabled:opacity-50"
                      >
                        <option value="">
                          {level3Options.length === 0
                            ? "—"
                            : "選択してください"}
                        </option>
                        {level3Options.map((node) => (
                          <option key={node.slug} value={node.slug}>
                            {node.name}
                          </option>
                        ))}
                      </select>
                      <FieldError
                        errors={showError ? field.state.meta.errors : []}
                      />
                    </Field>
                  );
                }}
              </form.Field>
            </div>
          </div>
        );
      }}
    </form.Subscribe>
  );
}

